1	export type Customer = { yearsWithMHPCO: number };
2	export type Item = {
3	  type: string;
4	  material?: string;
5	  enchantment?: number;
6	  cursed?: boolean;
7	};
8	export type Damage = { itemType: string; amount: number };
9	export type Incident = { cause: string; damages: Damage[] };
10	export type QuoteStep = { op: "quote"; items: Item[] };
11	export type ClaimStep = { op: "claim"; policy: number; incident: Incident };
12	export type Step = QuoteStep | ClaimStep;
13	export type Scenario = { customer: Customer; steps: Step[] };
14	export type QuoteResult = { premium: number };
15	export type ClaimResult = { payout: number; remainingCap: number };
16	export type ScenarioResult = { results: (QuoteResult | ClaimResult)[] };
17	
18	const PROCESSING_FEE = 5;
19	const FIRST_INSURANCE_RATE = 0.1;
20	
21	// Rounding policies — both round in MHPCO's favor
22	const roundPremiumInMHPCOFavor = Math.ceil;
23	const roundPayoutInMHPCOFavor = Math.floor;
24	
25	const BASE_PREMIUMS: Record<string, number> = {
26	  sword: 100,
27	  amulet: 60,
28	  staff: 80,
29	  potion: 40,
30	  rune: 25,
31	  moonstone: 25,
32	};
33	
34	const baseFor = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;
35	
36	const BLOCK_OF_3_PREMIUM = 60;
37	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
38	
39	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
40	
41	const countByType = <T>(entries: T[], key: (e: T) => string): Record<string, number> =>
42	  entries.reduce<Record<string, number>>((counts, entry) => {
43	    const k = key(entry);
44	    counts[k] = (counts[k] ?? 0) + 1;
45	    return counts;
46	  }, {});
47	
48	const componentBlockBase = (count: number, type: string): number =>
49	  count === 3 ? BLOCK_OF_3_PREMIUM : count * baseFor({ type });
50	
51	const componentsBase = (components: Item[]): number =>
52	  Object.entries(countByType(components, (item) => item.type)).reduce(
53	    (sum, [type, count]) => sum + componentBlockBase(count, type),
54	    0,
55	  );
56	
57	const sumBasePremiums = (items: Item[]): number => {
58	  const components = items.filter(isComponent);
59	  const standaloneBase = items
60	    .filter((item) => !isComponent(item))
61	    .reduce((sum, item) => sum + baseFor(item), 0);
62	  return componentsBase(components) + standaloneBase;
63	};
64	
65	const CURSE_RATE = 0.5;
66	const HIGH_ENCHANTMENT_RATE = 0.3;
67	const HIGH_ENCHANTMENT_THRESHOLD = 5;
68	
69	const isCursed = (item: Item): boolean => item.cursed === true;
70	const hasHighEnchantment = (item: Item): boolean =>
71	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
72	
73	const surchargeFor = (item: Item): number => {
74	  const base = baseFor(item);
75	  const curse = isCursed(item) ? base * CURSE_RATE : 0;
76	  const highEnch = hasHighEnchantment(item) ? base * HIGH_ENCHANTMENT_RATE : 0;
77	  return curse + highEnch;
78	};
79	
80	const itemSurcharges = (items: Item[]): number =>
81	  items.reduce((sum, item) => sum + surchargeFor(item), 0);
82	
83	const LOYALTY_RATE = 0.2;
84	const LOYALTY_THRESHOLD_YEARS = 2;
85	const FOLLOWUP_CONTRACT_RATE = 0.15;
86	
87	const isLoyal = (customer: Customer): boolean =>
88	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS;
89	
90	const loyaltyDiscount = (itemsBase: number, customer: Customer): number =>
91	  isLoyal(customer) ? itemsBase * LOYALTY_RATE : 0;
92	
93	const followupDiscount = (itemsBase: number, quoteIndex: number): number =>
94	  quoteIndex > 0 ? itemsBase * FOLLOWUP_CONTRACT_RATE : 0;
95	
96	const totalDiscounts = (itemsBase: number, customer: Customer, quoteIndex: number): number =>
97	  loyaltyDiscount(itemsBase, customer) + followupDiscount(itemsBase, quoteIndex);
98	
99	const isKnownItemType = (type: string): boolean => type in BASE_PREMIUMS;
100	
101	const assertKnownItemTypes = (items: Item[]): void => {
102	  for (const item of items) {
103	    if (!isKnownItemType(item.type)) {
104	      throw new Error(`unknown item type "${item.type}"`);
105	    }
106	  }
107	};
108	
109	const quotePremium = (items: Item[], customer: Customer, quoteIndex: number): number => {
110	  assertKnownItemTypes(items);
111	  const itemsBase = sumBasePremiums(items);
112	  const surcharges = itemSurcharges(items);
113	  const firstInsurance = itemsBase * FIRST_INSURANCE_RATE;
114	  const discounts = totalDiscounts(itemsBase, customer, quoteIndex);
115	  return roundPremiumInMHPCOFavor(itemsBase + surcharges + firstInsurance - discounts + PROCESSING_FEE);
116	};
117	
118	const INSURANCE_VALUES: Record<string, number> = {
119	  sword: 1000,
120	  amulet: 600,
121	  staff: 800,
122	  potion: 400,
123	  rune: 250,
124	  moonstone: 250,
125	};
126	
127	const insuranceValueFor = (item: Item): number => INSURANCE_VALUES[item.type] ?? 0;
128	
129	const insuranceSum = (items: Item[]): number =>
130	  items.reduce((sum, item) => sum + insuranceValueFor(item), 0);
131	
132	const DEDUCTIBLE = 100;
133	const CAP_MULTIPLIER = 2;
134	const CLAIM_HIGH_ENCHANTMENT_THRESHOLD = 8;
135	const CLAIM_HIGH_ENCHANTMENT_RATE = 0.5;
136	
137	const qualifiesForHighEnchantmentClause = (item: Item): boolean =>
138	  (item.enchantment ?? 0) >= CLAIM_HIGH_ENCHANTMENT_THRESHOLD;
139	
140	const reimbursableAmount = (item: Item, damageAmount: number): number =>
141	  qualifiesForHighEnchantmentClause(item)
142	    ? damageAmount * CLAIM_HIGH_ENCHANTMENT_RATE
143	    : damageAmount;
144	
145	const payoutForDamage = (item: Item, damageAmount: number): number =>
146	  reimbursableAmount(item, damageAmount) - DEDUCTIBLE;
147	
148	const findPolicyItem = (items: Item[], itemType: string): Item =>
149	  items.find((item) => item.type === itemType) as Item;
150	
151	const totalPayout = (damages: Damage[], policyItems: Item[]): number =>
152	  damages.reduce(
153	    (sum, damage) => sum + payoutForDamage(findPolicyItem(policyItems, damage.itemType), damage.amount),
154	    0,
155	  );
156	
157	type Policy = { items: Item[]; remainingCap: number };
158	
159	const openPolicy = (items: Item[]): Policy => ({
160	  items,
161	  remainingCap: insuranceSum(items) * CAP_MULTIPLIER,
162	});
163	
164	const validateDamagesAgainstPolicy = (damages: Damage[], items: Item[]): void => {
165	  const insuredCounts = countByType(items, (i) => i.type);
166	  const damageCounts = countByType(damages, (d) => d.itemType);
167	  for (const [type, damageCount] of Object.entries(damageCounts)) {
168	    const insuredCount = insuredCounts[type] ?? 0;
169	    if (damageCount > insuredCount) {
170	      throw new Error(
171	        insuredCount === 0
172	          ? `claim references "${type}" which is not covered by the policy`
173	          : `damages contain ${damageCount} entries for "${type}" but policy covers only ${insuredCount}`,
174	      );
175	    }
176	  }
177	};
178	
179	const assertNonNegativeDamages = (damages: Damage[]): void => {
180	  for (const damage of damages) {
181	    if (damage.amount < 0) {
182	      throw new Error(`damage amount must be non-negative, got ${damage.amount} for "${damage.itemType}"`);
183	    }
184	  }
185	};
186	
187	const claimAgainst = (policy: Policy, incident: Incident): ClaimResult => {
188	  assertNonNegativeDamages(incident.damages);
189	  validateDamagesAgainstPolicy(incident.damages, policy.items);
190	  const desiredPayout = roundPayoutInMHPCOFavor(totalPayout(incident.damages, policy.items));
191	  const payout = Math.min(desiredPayout, policy.remainingCap);
192	  return { payout, remainingCap: policy.remainingCap - payout };
193	};
194	
195	export const runScenario = (scenario: Scenario): ScenarioResult => {
196	  const policies: Policy[] = [];
197	  const results = scenario.steps.map((step) => {
198	    if (step.op === "quote") {
199	      const premium = quotePremium(step.items, scenario.customer, policies.length);
200	      policies.push(openPolicy(step.items));
201	      return { premium };
202	    }
203	    const result = claimAgainst(policies[step.policy], step.incident);
204	    policies[step.policy] = { ...policies[step.policy], remainingCap: result.remainingCap };
205	    return result;
206	  });
207	  return { results };
208	};
